def kth_ordered(words, k):
    if not words or k <= 0:
        return None

    # Group words by their length
    grouped_words = {}
    for word in words:
        length = len(word)
        if length not in grouped_words:
            grouped_words[length] = []
        grouped_words[length].append(word)

    sorted_words = []
    # Sort words of the same length reverse-alphabetically and add to the result list
    for length in sorted(grouped_words.keys()):
        sorted_words.extend(sorted(grouped_words[length], reverse=True))

    # Return k-th word if within range, otherwise None
    if k <= len(sorted_words):
        return sorted_words[k - 1]
    else:
        return None
